const Sentry = require('@sentry/node');
const https = require('https');

const input = $('Start').first().json;
const { to, subject, html, tenant_id } = input;
const inputFrom = input.from;

if (!to || !subject || !html) {
  throw new Error(`[Send Email] Missing required fields: to=${!!to}, subject=${!!subject}, html=${!!html}`);
}

const configItems = $('Fetch Email Config').all();
const config = configItems.length > 0 && configItems[0].json?.id ? configItems[0].json : null;

let apiKey, fromAddress, provider;

if (config && config.is_active) {
  provider = config.provider;
  apiKey = config.api_key;
  fromAddress = inputFrom || (config.from_name ? `${config.from_name} <${config.from_email}>` : config.from_email);
} else {
  provider = 'resend';
  apiKey = 're_hnLgw1AZ_F35kBpnkpjuSrG7PUBaDpWnK';
  fromAddress = inputFrom || 'Halo Efekt <noreply@haloefekt.pl>';
  Sentry.captureMessage(`[Send Email] No active email config for tenant ${tenant_id}, using default`, 'warning');
  await Sentry.flush(2000);
}

if (provider !== 'resend') {
  throw new Error(`[Send Email] Unsupported provider: ${provider}. Only 'resend' is supported.`);
}

const recipients = Array.isArray(to) ? to : [to];
const postData = JSON.stringify({ from: fromAddress, to: recipients, subject, html });

const result = await new Promise((resolve, reject) => {
  const req = https.request({
    hostname: 'api.resend.com',
    path: '/emails',
    method: 'POST',
    headers: {
      'Authorization': `Bearer ${apiKey}`,
      'Content-Type': 'application/json',
      'Content-Length': Buffer.byteLength(postData)
    }
  }, (res) => {
    let body = '';
    res.on('data', (chunk) => body += chunk);
    res.on('end', () => {
      try {
        const parsed = JSON.parse(body);
        if (res.statusCode >= 400) {
          reject(new Error(`[Send Email] ${provider} error: ${JSON.stringify(parsed)}`));
        } else {
          resolve(parsed);
        }
      } catch (e) {
        reject(new Error(`[Send Email] Parse error: ${body}`));
      }
    });
  });
  req.on('error', reject);
  req.write(postData);
  req.end();
});

return { id: result.id, to: recipients, subject, provider };
